sys_ux_client_script.script:
/**
 * @param {params} params
 * @param {api} params.api
 * @param {any} params.event
 * @param {any} params.imports
 * @param {ApiHelpers} params.helpers
 */
function handler({
    api,
    event,
    helpers,
    imports
}) {
    const nf = imports['x_snc_nf.NextFormUtil']();
    const skipValidation = event && event.payload && event.payload.skipValidation === true;
    const onLast = api.state.currentScreenNumber === api.state.screenCount;

    if (!onLast) {
        return;
    }

    if (!skipValidation) {
        if (!api.state.canProcess || api.state.isProcessed) {
            api.setState('canProcess', false);
            return;
        }
        const fieldsForValidation = nf.cloneFieldsMap(api.state.fields);
        const vr = nf.validateAllFields(fieldsForValidation);
        api.setState('fields', fieldsForValidation);
        api.setState('canProcess', nf.canProcess({
            currentScreenNumber: api.state.currentScreenNumber,
            screenCount: api.state.screenCount,
            isProcessed: api.state.isProcessed
        }, vr));
        if (!vr.allOk) {
            return;
        }
    }

    api.emit('CTRL_NEXTFORM#PROCESSING_STARTED');

    const fields = api.state.fields;
    const processEditedOnly = api.context.props.processEditedOnly === true;
    let nfData = {};

    Object.keys(fields).forEach(function(key) {
        const field = fields[key];
        if (field.isDataField !== false && (!processEditedOnly ||
            (Object.hasOwn(field, 'originalValue') && field.originalValue !== field.value))) {
            nfData[field.name] = {
                name: field.name,
                value: field.value,
                displayValue: field.displayValue
            };
        }
    });

    let payload = {
        nextform_id: api.context.props.nextFormSysId,
        nextform_data: JSON.stringify(nfData)
    };
    let meta;
    if (api.context.props.metadata) {
        meta = {};
        Object.keys(api.context.props.metadata).forEach(key => {
            meta[key] = api.context.props.metadata[key];
        });
        payload.metadata = JSON.stringify(meta);
    }

    api.data.process_nextform_data.execute(payload);
}
